class Solution:
    def minSizeSubarray(self, nums, target):
        best = -1
        min_val = min(nums)
        max_copies = target // min_val + 3
        arr = []
        while len(arr) < max_copies * len(nums):
            arr.extend(nums)
        L = len(arr)
        for i in range(L):
            s = 0
            for j in range(i, L):
                s += arr[j]
                if s == target:
                    length = j - i + 1
                    if best == -1 or length < best:
                        best = length
                    break
                if s > target:
                    break
        return best

