class Solution:
    def minSizeSubarray(self, nums, target):
        n = len(nums)
        total = sum(nums)
        if target % total == 0:
            q = target // total - 1
            r = total
        else:
            q = target // total
            r = target % total
        doubled = nums + nums
        best = None
        left = 0
        s = 0
        for right in range(len(doubled)):
            s += doubled[right]
            while s > r:
                s -= doubled[left]
                left += 1
            if s == r:
                length = right - left + 1
                if best is None or length < best:
                    best = length
        if best is None:
            return -1
        return q * n + best

