var minSizeSubarray = function(nums, target) {
    const n = nums.length;
    const total = nums.reduce((a, b) => a + b, 0);
    let q, r;
    if (target % total === 0) {
        q = Math.floor(target / total) - 1;
        r = total;
    } else {
        q = Math.floor(target / total);
        r = target % total;
    }
    const doubled = nums.concat(nums);
    let best = -1;
    let left = 0, s = 0;
    for (let right = 0; right < doubled.length; right++) {
        s += doubled[right];
        while (s > r) {
            s -= doubled[left];
            left++;
        }
        if (s === r) {
            const length = right - left + 1;
            if (best === -1 || length < best) best = length;
        }
    }
    if (best === -1) return -1;
    return q * n + best;
};
